const base = ($env.DITTO_BASE_URL || 'http://docker-nginx-1').replace(/\/$/, '');
const thingId = $env.PRIMARY_THING_ID || 'building:floor1:elevator';
const user = $env.DITTO_USERNAME || 'ditto';
const pass = $env.DITTO_PASSWORD || 'ditto';
const auth = 'Basic ' + Buffer.from(`${user}:${pass}`).toString('base64');
const now = new Date().toISOString();

let ditto = { component: 'ditto', status: 'DOWN', latency_ms: 0, error_message: '' };
const t0 = Date.now();
try {
  await $http.request({
    method: 'GET',
    url: `${base}/api/2/things/${thingId}`,
    headers: { accept: 'application/json', Authorization: auth },
    timeout: 4000
  });
  ditto.status = 'UP';
} catch (e) {
  ditto.error_message = String((e && e.message) || 'ditto_unreachable').slice(0, 200);
}
ditto.latency_ms = Date.now() - t0;

// Postgres reachability is proven by the upstream Probe Postgres node succeeding;
// n8n is UP because this Code node is executing.
return [
  { json: { thing_id: thingId, ...ditto, checked_at: now } },
  { json: { thing_id: thingId, component: 'postgres', status: 'UP', latency_ms: 0, error_message: '', checked_at: now } },
  { json: { thing_id: thingId, component: 'n8n', status: 'UP', latency_ms: 0, error_message: '', checked_at: now } }
];
